#include <cstdint>\n#include <iostream>\n#include <vector>\n\nclass Graph {\n public:\n  Graph(size_t n, const std::vector<std::pair<size_t, size_t>>& edges) {\n    table_.resize(n + 1);\n    tin_.resize(n + 1, 0);\n    tout_.resize(n + 1, 0);\n    Build(edges);\n  }\n\n  std::vector<size_t> TopSort() {\n    for (size_t i = 1; i < table_.size(); i++) {\n      if (!is_top_sortable_) {\n        return vertexes_;\n      }\n      if (GetColor(i) == Colors_::White) {\n        Dfs(i);\n      }\n    }\n\n    if (!is_top_sortable_) {\n      return vertexes_;\n    }\n    vertexes_.resize(tout_.size());\n    for (size_t i = 0; i < vertexes_.size(); i++) {\n      vertexes_[i] = i;\n    }\n    // сортировка вершин в порядке убывания\n    HeapSort();\n    return vertexes_;\n  }\n\n private:\n  void Dfs(size_t start) {\n    if (!is_top_sortable_) {\n      return;\n    }\n    tin_[start] = time_++;\n    const std::vector<size_t>& children = table_[start];\n    for (auto i : children) {\n      switch (GetColor(i)) {\n        case Colors_::White:\n          Dfs(i);\n          break;\n        case Colors_::Gray:\n          is_top_sortable_ = false;\n          return;\n        case Colors_::Black:\n          break;\n      }\n    }\n    tout_[start] = time_++;\n  }\n\n  void Build(const std::vector<std::pair<size_t, size_t>>& edges) {\n    for (const std::pair<size_t, size_t>& pair : edges) {\n      table_[pair.first].push_back(pair.second);\n    }\n  }\n\n  enum class Colors_;\n  Colors_ GetColor(size_t start) {\n    if (tin_[start] == 0) {\n      return Colors_::White;\n    }\n    if (tout_[start] == 0) {\n      return Colors_::Gray;\n    }\n    return Colors_::Black;\n  }\n\n  void HeapSort() {\n    auto size = vertexes_.size();\n    for (size_t i = size / 2 - 1; i >= 1; i--) {\n      SiftDown(i, size);\n    }\n    SiftDown(0, size);\n    for (size_t i = size - 1; i >= 1; i--) {\n      std::swap(tout_[0], tout_[i]);\n      std::swap(vertexes_[0], vertexes_[i]);\n      SiftDown(0, i);\n    }\n  }\n\n  void SiftDown(size_t index, size_t size) {\n    size_t left = index * 2 + 1;\n    size_t right = left + 1;\n    size_t min_index = index;\n    if (left < size && tout_[left] < tout_[min_index]) {\n      min_index = left;\n    }\n    if (right < size && tout_[right] < tout_[min_index]) {\n      min_index = right;\n    }\n    if (index == min_index) {\n      return;\n    }\n    std::swap(vertexes_[index], vertexes_[min_index]);\n    std::swap(tout_[index], tout_[min_index]);\n    SiftDown(min_index, size);\n  }\n\n  bool is_top_sortable_ = true;\n  size_t time_ = 1;\n  std::vector<std::vector<size_t>> table_;\n  std::vector<size_t> tin_;\n  std::vector<size_t> tout_;\n  std::vector<size_t> vertexes_;\n  enum class Colors_ { White, Gray, Black };\n};\n\nint main() {\n  size_t n = 0;\n  size_t m = 0;\n  std::cin >> n >> m;\n  std::vector<std::pair<size_t, size_t>> edges(m);\n  for (size_t it = 0; it < m; it++) {\n    size_t i = 0;\n    size_t j = 0;\n    std::cin >> i >> j;\n    edges[it] = {i, j};\n  }\n\n  Graph graph(n, edges);\n  auto vertexes = graph.TopSort();\n\n  if (vertexes.empty()) {\n    std::cout << -1 << std::endl;\n  } else {\n    for (auto i : vertexes) {\n      if (i != 0) {\n        std::cout << i << ' ';\n      }\n    }\n    std::cout << std::endl;\n  }\n  return 0;\n}\n